/**
 * EmptyState — spec §10.1, §17
 *
 * Variants:
 *  - hint (first-use): illustration + heading + helper + optional CTA
 *  - filtered: helper + "Clear filters" link
 *  - error: alert + retry CTA
 *  - end: centered "• End of list •" terminator
 */
import * as React from 'react';
import { Alert, Box, Stack, Typography } from '@mui/material';
import { semanticColors } from '@/constants/ThemeConstants';

export type EmptyStateVariant = 'hint' | 'filtered' | 'error' | 'end';

export interface EmptyStateProps {
    variant?: EmptyStateVariant;
    /** Visual element above the heading (illustration / icon). hint variant only. */
    illustration?: React.ReactNode;
    /** h5 heading. Required for `hint`; ignored for `end`. */
    heading?: React.ReactNode;
    /** body2 helper text describing what's missing and what to do next. */
    helper?: React.ReactNode;
    /** Primary CTA (button) — typically only on `hint` and `error`. */
    action?: React.ReactNode;
    /** Optional request/correlation id surfaced in error variant caption. */
    correlationId?: string;
}

export const EmptyState: React.FC<EmptyStateProps> = ({
    variant = 'hint',
    illustration,
    heading,
    helper,
    action,
    correlationId,
}) => {
    if (variant === 'end') {
        return (
            <Typography
                variant="body2"
                role="status"
                aria-live="polite"
                sx={{
                    color: semanticColors.text.secondary,
                    textAlign: 'center',
                    py: 3,
                }}
            >
                {helper ?? '• End of list •'}
            </Typography>
        );
    }

    if (variant === 'error') {
        return (
            <Alert
                severity="error"
                role="alert"
                action={action}
                sx={{ width: '100%' }}
            >
                {helper ?? "Something went wrong. Please try again."}
                {correlationId && (
                    <Typography
                        component="div"
                        variant="caption"
                        sx={{ mt: 0.5, color: semanticColors.text.muted }}
                    >
                        Ref: {correlationId}
                    </Typography>
                )}
            </Alert>
        );
    }

    return (
        <Stack
            direction="column"
            spacing={2}
            role="status"
            aria-live="polite"
            sx={{
                alignItems: 'center',
                py: { xs: 4, md: 6 },
                px: 2,
                textAlign: 'center',
                color: semanticColors.text.secondary,
            }}
        >
            {variant === 'hint' && illustration && (
                <Box aria-hidden="true" sx={{ color: semanticColors.text.muted }}>
                    {illustration}
                </Box>
            )}
            {heading && (
                <Typography
                    variant="h5"
                    component="p"
                    sx={{ color: semanticColors.text.primary, fontWeight: 600 }}
                >
                    {heading}
                </Typography>
            )}
            {helper && (
                <Typography variant="body2" sx={{ maxWidth: 480 }}>
                    {helper}
                </Typography>
            )}
            {action && <Box>{action}</Box>}
        </Stack>
    );
};

export default EmptyState;
